(async () => {
  const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  const waitFor = async (fn, timeoutMs = 4000, stepMs = 50) => {
    const deadline = Date.now() + timeoutMs;
    while (Date.now() < deadline) {
      const value = fn();
      if (value) return value;
      await wait(stepMs);
    }
    return null;
  };
  const ensureFile = async (path, text) => {
    const existing = app.vault.getAbstractFileByPath(path);
    if (existing) {
      await app.vault.modify(existing, text);
      return existing;
    }
    return app.vault.create(path, text);
  };
  const plugin = app.plugins.plugins["block-link-plus"];
  if (!plugin) throw new Error("block-link-plus plugin not loaded");
  const prevSettings = {
    inlineEditEnabled: plugin.settings.inlineEditEnabled,
    inlineEditBlock: plugin.settings.inlineEditBlock,
    inlineEditHeading: plugin.settings.inlineEditHeading,
    inlineEditFile: plugin.settings.inlineEditFile,
  };
  const folder = "_blp_tmp/issue-36";
  if (!app.vault.getAbstractFileByPath("_blp_tmp")) await app.vault.createFolder("_blp_tmp");
  if (!app.vault.getAbstractFileByPath(folder)) await app.vault.createFolder(folder);
  const sourcePath = `${folder}/embed-source.md`;
  const hostPath = `${folder}/host-scroll.md`;
  const sourceLines = [];
  for (let i = 1; i <= 80; i += 1) {
    sourceLines.push(`- source block ${i} ^b${i}`);
  }
  await ensureFile(sourcePath, sourceLines.join("\n"));
  const embeds = [10, 20, 30, 40, 50, 60].map((n) => `![[${sourcePath}#^b${n}]]`);
  const hostLines = [
    "# Issue 36 host",
    "",
    ...Array.from({ length: 18 }, (_, i) => `intro filler ${i + 1}`),
    ...embeds.flatMap((embed, i) => [embed, "", `between filler ${i + 1}`, ""]),
    ...Array.from({ length: 90 }, (_, i) => `tail filler ${i + 1}`),
  ];
  const hostFile = await ensureFile(hostPath, hostLines.join("\n"));
  const leaf = app.workspace.getLeaf(false);
  await leaf.openFile(hostFile, { active: true, state: { mode: "source" } });
  app.workspace.setActiveLeaf?.(leaf, { focus: true });
  const view = leaf.view;
  plugin.settings.inlineEditEnabled = true;
  plugin.settings.inlineEditBlock = true;
  plugin.settings.inlineEditHeading = false;
  plugin.settings.inlineEditFile = false;
  plugin.inlineEditEngine?.onSettingsChanged?.();
  await wait(1200);
  const cm = view.editor.cm;
  const scroller = cm.scrollDOM;
  const snapshot = (label) => ({
    label,
    scrollTop: scroller.scrollTop,
    scrollHeight: scroller.scrollHeight,
    clientHeight: scroller.clientHeight,
    hostEmbeds: view.containerEl.querySelectorAll(".internal-embed.markdown-embed").length,
    activeInlineEmbeds: view.containerEl.querySelectorAll(".internal-embed.markdown-embed.blp-inline-edit-active").length,
    embeddedRoots: view.containerEl.querySelectorAll(".blp-inline-edit-root").length,
    firstVisibleText: document
      .elementFromPoint(scroller.getBoundingClientRect().left + 40, scroller.getBoundingClientRect().top + 40)
      ?.textContent?.slice(0, 80) ?? null,
  });
  const samples = [];
  samples.push(snapshot("after-open"));
  scroller.scrollTop = Math.max(0, Math.floor(scroller.scrollHeight * 0.62));
  cm.requestMeasure?.();
  await wait(250);
  samples.push(snapshot("after-manual-scroll"));
  const beforeRemount = scroller.scrollTop;
  view.containerEl.querySelectorAll(".blp-inline-edit-root").forEach((root) => root.remove());
  view.containerEl.querySelectorAll(".internal-embed.markdown-embed.blp-inline-edit-active").forEach((embed) => {
    embed.classList.remove("blp-inline-edit-active");
  });
  plugin.inlineEditEngine?.refreshLivePreviewObservers?.(true);
  await waitFor(() => view.containerEl.querySelectorAll(".blp-inline-edit-root").length >= 4, 5000);
  await wait(600);
  samples.push(snapshot("after-forced-remount"));
  const afterRemount = scroller.scrollTop;
  plugin.settings.inlineEditEnabled = false;
  plugin.inlineEditEngine?.onSettingsChanged?.();
  await wait(500);
  scroller.scrollTop = beforeRemount;
  await wait(100);
  samples.push(snapshot("after-disable-inline-edit-reset-scroll"));
  plugin.settings.inlineEditEnabled = true;
  plugin.settings.inlineEditBlock = true;
  plugin.inlineEditEngine?.onSettingsChanged?.();
  await wait(1200);
  samples.push(snapshot("after-reenable-inline-edit"));
  const afterReenable = scroller.scrollTop;
  Object.assign(plugin.settings, prevSettings);
  plugin.inlineEditEngine?.onSettingsChanged?.();
  await plugin.saveSettings?.();
  return {
    ok: true,
    runtime: {
      title: document.title,
      vault: app.vault.getName(),
      activeFile: app.workspace.getActiveFile()?.path,
      obsidianVersion: app.getVersion?.() ?? null,
    },
    settingsUsed: {
      inlineEditEnabled: true,
      inlineEditBlock: true,
      inlineEditHeading: false,
      inlineEditFile: false,
    },
    deltas: {
      beforeRemount,
      afterRemount,
      remountDelta: afterRemount - beforeRemount,
      afterReenable,
      reenableDelta: afterReenable - beforeRemount,
    },
    samples,
  };
})();

